code.C:
#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    for(int i=0;i<T;++i){
        double l,w; scanf("%lf %lf", &l, &w);
        double length = fabs(l);
        double width  = fabs(w);
        double area   = length * width;
        printf("Length: %.1f\n", length);
        printf("Width: %.1f\n", width);
        printf("Area: %.1f\n", area);
    }
    return 0;
}

