const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (input.length === 0) process.exit(0);
let idx = 0;
const T = parseInt(input[idx++], 10);
let out = [];
for (let i = 0; i < T; i++) {
  const l = parseFloat(input[idx++]);
  const w = parseFloat(input[idx++]);
  const length = Math.abs(l);
  const width = Math.abs(w);
  const area = length * width;
  out.push(`Length: ${length.toFixed(1)}`);
  out.push(`Width: ${width.toFixed(1)}`);
  out.push(`Area: ${area.toFixed(1)}`);
}
console.log(out.join('\n'));

